SELECT

FROM sys_login_log


        AND username LIKE CONCAT('%', #{username}, '%')


        AND login_ip LIKE CONCAT('%', #{loginIp}, '%')


        AND login_status = #{loginStatus}


        AND login_time >= #{loginTimeStart}


        AND login_time <= #{loginTimeEnd}


        AND tenant_id = #{tenantId}


        AND client_id LIKE CONCAT('%', #{clientId}, '%')


ORDER BY login_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM sys_login_log


        AND username LIKE CONCAT('%', #{username}, '%')


        AND login_ip LIKE CONCAT('%', #{loginIp}, '%')


        AND login_status = #{loginStatus}


        AND login_time >= #{loginTimeStart}


        AND login_time <= #{loginTimeEnd}


        AND tenant_id = #{tenantId}


        AND client_id LIKE CONCAT('%', #{clientId}, '%')
